import{_ as t,o as a,c as n,ag as s}from"./chunks/framework.BOaOek6C.js";const g=JSON.parse('{"title":"Layout and application shell","description":"","frontmatter":{},"headers":[],"relativePath":"addons/md/layout-and-shell.md","filePath":"addons/md/layout-and-shell.md"}'),o={name:"addons/md/layout-and-shell.md"};function r(l,e,i,p,h,d){return a(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="layout-and-application-shell" tabindex="-1">Layout and application shell <a class="header-anchor" href="#layout-and-application-shell" aria-label="Permalink to &quot;Layout and application shell&quot;">​</a></h1><p>This page describes the <strong>big picture</strong> users see when MdEditor is open.</p><h2 id="regions-of-the-screen" tabindex="-1">Regions of the screen <a class="header-anchor" href="#regions-of-the-screen" aria-label="Permalink to &quot;Regions of the screen&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>+------------------+------------------------------+</span></span>
<span class="line"><span>|                  | Primary nav + context bar   |</span></span>
<span class="line"><span>|  Left sidebar    +------------------------------+</span></span>
<span class="line"><span>|  (~300px)        | Main content  | Right rail |</span></span>
<span class="line"><span>|                  | (your page)   | (optional)|</span></span>
<span class="line"><span>+------------------+------------------------------+</span></span></code></pre></div><p>(Full window height; the left column and the block on the right share the same vertical space.)</p><ol><li><p><strong>Left sidebar</strong></p><ul><li>Runs from the <strong>top</strong> of the window to the <strong>bottom</strong> (not only below the bars on the right).</li><li>Contains <strong>branding</strong> (mdEditor-style wordmark, version, help) and <strong>collapsible sections</strong> (accordion navigation).</li><li>On <strong>small screens</strong>, it can hide off-screen and reopen via a <strong>menu (hamburger) button</strong> in the primary navigation.</li></ul></li><li><p><strong>Main column</strong> (everything to the right of the left sidebar)</p><ul><li><strong>Chrome:</strong><ul><li><strong>Primary navigation</strong> — global routes (Dashboard, Export, Import, Publish, Sync) and <strong>Settings</strong> on the right.</li><li><strong>Context title bar</strong> — a light strip that reflects the current area (e.g. “Dashboard,” “Records”).</li></ul></li><li><strong>Body:</strong><ul><li><strong>Main content</strong> — where each route renders (your page).</li><li><strong>Right sidebar</strong> — optional rail for supplemental panels (placeholders today in the template).</li></ul></li></ul></li></ol><h2 id="who-owns-the-layout" tabindex="-1">Who owns the layout? <a class="header-anchor" href="#who-owns-the-layout" aria-label="Permalink to &quot;Who owns the layout?&quot;">​</a></h2><p>The <strong><code>Md::AppShell</code></strong> component defines this structure. The MdEditor <strong><code>application</code></strong> template fills in each “slot” (left rail, primary nav, etc.) with concrete content.</p><h2 id="responsiveness" tabindex="-1">Responsiveness <a class="header-anchor" href="#responsiveness" aria-label="Permalink to &quot;Responsiveness&quot;">​</a></h2><ul><li><strong>Wide screens:</strong> Left sidebar stays visible at about <strong>300px</strong> width.</li><li><strong>Narrow screens:</strong> Sidebar becomes a <strong>drawer</strong> with a dimmed <strong>backdrop</strong>; the host app tracks open/closed state and closes the drawer when the backdrop is clicked.</li></ul><p>For argument names and technical detail, see <a href="./components/app-shell.html">App shell</a>.</p>`,11)])])}const u=t(o,[["render",r]]);export{g as __pageData,u as default};
